public function isMobileOrder($order_id = 0) {
  $result = $this->db->query("SELECT mobikul FROM " . DB_PREFIX . "order WHERE order_id = '" . (int)$this->db->escape($order_id) . "'")->row;
  if (isset($result['mobikul']) && $result['mobikul'] == 1) {
    return true;
  }
  return false;
}
